"const fs = require('fs');
const path = require('path');

const brainDir = 'C:\\Users\\paulo\\.gemini\\antigravity\\brain';
const targetFile = 'transcript.jsonl';

function searchTranscripts() {
  const dirs = fs.readdirSync(brainDir);
  for (const dir of dirs) {
    const logPath = path.join(brainDir, dir, '.system_generated', 'logs', targetFile);
    if (!fs.existsSync(logPath)) continue;

    console.log('Verificando conversa:', dir);
    try {
      const content = fs.readFileSync(logPath, 'utf8');
      const lines = content.split('\n');
      let foundCount = 0;

      for (let i = 0; i < lines.length; i++) {
        const line = lines[i];
        if (line.includes('CompanyDashboard.tsx') && line.includes('replace_file_content')) {
          foundCount++;
          // Grava a linha correspondente em um arquivo do scratch para analisarmos
          fs.writeFileSync(`C:\\Users\\paulo\\antigravity\\Colaborh---Conectando-Talentos\\scratch\\match_${dir}_line_${i}.json`, line, 'utf8');
        }
      }
      console.log(`[${dir}] Encontrados ${foundCount} matches.`);
    } catch (e) {
      console.error(`Erro ao ler log da conversa ${dir}:`, e.message);
    }
  }
}

searchTranscripts();
"
